mapper.select:
SELECT u.user_id AS userId, u.user_name AS userName, u.real_name AS realName, u.role_id AS roleId, u.role_name AS roleName, u.dept_id AS deptId, u.dept_name AS deptName, u.phone AS phone, u.email AS email, u.status AS status, CASE u.status WHEN 1 THEN '启用' WHEN 0 THEN '禁用' ELSE '未知' END AS statusText, u.last_login_time AS lastLoginTime, u.create_time AS createTime FROM sys_user u WHERE u.is_deleted = 0
AND ( u.user_name LIKE CONCAT('%', #{req.keyword}, '%') OR u.real_name LIKE CONCAT('%', #{req.keyword}, '%') OR u.phone LIKE CONCAT('%', #{req.keyword}, '%') )
AND u.role_id = #{req.roleId}
AND u.dept_id = #{req.deptId}
AND u.status = #{statusCode}
ORDER BY u.update_time DESC, u.user_id DESC

SELECT COUNT(1)
FROM sys_user u
WHERE u.user_name = #{userName}
  AND u.is_deleted = 0

    AND u.user_id != #{excludeUserId}

SELECT COUNT(1)
FROM sys_role_permission rp
WHERE rp.role_id = #{roleId}
  AND rp.is_deleted = 0
  AND rp.permission_code IN

    #{permissionCode}
